/* ===== 失效反馈功能（开关：tctipFeedback.enabled） ===== */
var tctipFeedback=(function(){
var enabled=true; // 开关：false 则不初始化
var FEISHU_BASE='https://my.feishu.cn/share/base/form/shrcnQEQph33whiOEjpqKiXMdeh';
var selectMode=false,btn;

function init(){
if(!enabled)return;
// 注入样式
var s=document.createElement('style');
s.textContent=
'#feedbackBtn{position:fixed;right:0;top:55%;z-index:9998;width:30px;min-width:30px;background:#323d45;color:#fff;border:0;padding:1em 0;font:13px/1.4 "microsoft yahei",arial,sans-serif;cursor:pointer;border-radius:12px;border-top-right-radius:0;border-bottom-right-radius:0;writing-mode:vertical-rl;letter-spacing:2px;white-space:nowrap;overflow:visible}'
+'.myRewards{top:40%!important;transform:translateY(-50%)!important;pointer-events:none}'
+'.myRewards .btn-myRewards,.myRewards-main{pointer-events:auto}'
+'#feedbackBtn:hover{background:#454e57}'
+'#feedbackBtn.active{background:#d9534f}'
+'#feedbackBtn.active:hover{background:#c9302c}'
+'body.feedback-select-mode #mainmenu a[href],body.feedback-select-mode #mainmenu a[HREF]{outline:2px dashed #d9534f!important}'
+'body.feedback-select-mode #mainmenu a[href]:hover,body.feedback-select-mode #mainmenu a[HREF]:hover{background:#ffe5e0!important}'
+'body.feedback-select-mode::after{content:"点击带链接的资源进行反馈，「点击右下角」或按「Esc键」退出选择模式";position:fixed;left:0;right:0;bottom:0;background:#d9534f;color:#fff;text-align:center;font:13px/2 "microsoft yahei",arial,sans-serif;z-index:9999}';
document.head.appendChild(s);
// 创建按钮
btn=document.createElement('button');
btn.id='feedbackBtn';btn.textContent='失效反馈';
document.body.appendChild(btn);
// 事件
btn.addEventListener('click',toggleSelectMode);
document.addEventListener('keydown',function(e){if(e.key==='Escape'&&selectMode)toggleSelectMode();});
document.addEventListener('click',onClick,false);
}

function toggleSelectMode(){
selectMode=!selectMode;
document.body.classList.toggle('feedback-select-mode',selectMode);
btn.textContent=selectMode?'退出选择模式':'失效反馈';
btn.classList.toggle('active',selectMode);
}

function buildPath(a){
var nums=[],li=a.closest('li'),node=li?li.parentElement:null;
while(node&&node!==document.body){
if(node.tagName==='LI'){
var fa=node.querySelector(':scope > a');
if(fa){var m=(fa.textContent||'').match(/^\s*(\d+)/);if(m)nums.unshift(parseInt(m[1],10));}
}
node=node.parentElement;
}
return nums.join('-')+'栏';
}

function isTarget(a){
if(!a||a.tagName!=='A')return false;
var h=a.getAttribute('href')||a.getAttribute('HREF');if(!h)return false;
if(a.querySelector('img.bei'))return false;
if(!(a.textContent||'').trim())return false;
var li=a.closest('li');if(li&&li.querySelector(':scope > ul.menu'))return false;
return true;
}

function onClick(e){
if(!selectMode)return;
if(!e.target.closest('#mainmenu'))return;
var a=e.target.closest('a');if(!a||!isTarget(a))return;
e.preventDefault();
var name=(a.textContent||a.innerText||'').trim();
var path=buildPath(a);
var url=FEISHU_BASE+'?prefill_失效资源名称='+name+'&prefill_所在目录路径='+path;
if(confirm('确认反馈以下失效资源？\n\n失效资源名称：'+name+'\n所在目录路径：'+path+'\n\n点击「确定」将跳转至飞书问卷。')){
toggleSelectMode();window.open(url,'_blank');
}
}

return{init:init,
isEnabled:function(){return enabled;},
enable:function(){enabled=true;init();},
disable:function(){enabled=false;}
};
})();

if(tctipFeedback.isEnabled()){tctipFeedback.init();}